"use strict";(self.webpackChunkblog=self.webpackChunkblog||[]).push([[6233],{1836:(e,a,n)=>{n.r(a),n.d(a,{data:()=>d});const d={key:"v-14961d54",path:"/leetcode/dayOne/1734.%20%E8%A7%A3%E7%A0%81%E5%BC%82%E6%88%96%E5%90%8E%E7%9A%84%E6%8E%92%E5%88%97.html",title:"",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"解码异或后的排列",slug:"解码异或后的排列",children:[{level:3,title:"示例 1：",slug:"示例-1",children:[]},{level:3,title:"示例 2：",slug:"示例-2",children:[]}]},{level:2,title:"分析",slug:"分析",children:[]}],filePathRelative:"leetcode/dayOne/1734. 解码异或后的排列.md",git:{updatedTime:1623368229e3,contributors:[{name:"atrist",email:"atristmu@outlook.com",commits:1}]}}},6540:(e,a,n)=>{n.r(a),n.d(a,{default:()=>r});const d=(0,n(6252).uE)('<h2 id="解码异或后的排列" tabindex="-1"><a class="header-anchor" href="#解码异或后的排列" aria-hidden="true">#</a> 解码异或后的排列</h2><p>给你一个整数数组 perm ，它是前 n 个正整数的排列，且 n 是个 <strong>奇数</strong> 。</p><p>它被加密成另一个长度为 <code>n - 1</code> 的整数数组 encoded ，满足 <code>encoded[i] = perm[i] XOR perm[i + 1]</code> 。比方说，如果 perm = [1,3,2] ，那么 encoded = [2,1] 。</p><p>给你 <code>encoded</code> 数组，请你返回原始数组 perm 。题目保证答案存在且唯一。</p><h3 id="示例-1" tabindex="-1"><a class="header-anchor" href="#示例-1" aria-hidden="true">#</a> 示例 1：</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>输入：encoded = [3,1]\n输出：[1,2,3]\n解释：如果 perm = [1,2,3] ，那么 encoded = [1 XOR 2,2 XOR 3] = [3,1]\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="示例-2" tabindex="-1"><a class="header-anchor" href="#示例-2" aria-hidden="true">#</a> 示例 2：</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>输入：encoded = [6,5,4,6]\n输出：[2,4,1,5,3]\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="分析" tabindex="-1"><a class="header-anchor" href="#分析" aria-hidden="true">#</a> 分析</h2>',9),r={render:function(e,a){return d}}}}]);